//go:build ignore

// gen_wasm_main.go writes the pre-compiled WASM fixture files used by wazero_exec_test.go.
// Run: go run gen_wasm_main.go
package main

import "os"

func main() {
	// echo_transform.wasm — alloc always returns 0; transform echoes (ptr<<32)|len.
	echoTransformWASM := []byte{
		0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
		// type section: type[0] (i32)->i32, type[1] (i32,i32)->i64
		0x01, 0x0c, 0x02,
		0x60, 0x01, 0x7f, 0x01, 0x7f,
		0x60, 0x02, 0x7f, 0x7f, 0x01, 0x7e,
		// function section: func[0]=type[0], func[1]=type[1]
		0x03, 0x03, 0x02, 0x00, 0x01,
		// memory section: (memory 1)
		0x05, 0x03, 0x01, 0x00, 0x01,
		// export section: "memory" mem[0], "alloc" func[0], "transform" func[1]
		0x07, 0x1e, 0x03,
		0x06, 0x6d, 0x65, 0x6d, 0x6f, 0x72, 0x79, 0x02, 0x00,
		0x05, 0x61, 0x6c, 0x6c, 0x6f, 0x63, 0x00, 0x00,
		0x09, 0x74, 0x72, 0x61, 0x6e, 0x73, 0x66, 0x6f, 0x72, 0x6d, 0x00, 0x01,
		// code section: 2 functions
		0x0a, 0x13, 0x02,
		// alloc body: i32.const 0, end
		0x04, 0x00, 0x41, 0x00, 0x0b,
		// transform body: (ptr<<32)|len
		0x0c, 0x00,
		0x20, 0x00, // local.get 0 (ptr)
		0xad,       // i64.extend_i32_u
		0x42, 0x20, // i64.const 32
		0x86,       // i64.shl
		0x20, 0x01, // local.get 1 (len)
		0xad,       // i64.extend_i32_u
		0x84,       // i64.or
		0x0b,       // end
	}

	// infinite_loop.wasm — transform loops forever; alloc returns 0.
	infiniteLoopWASM := []byte{
		0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
		0x01, 0x0c, 0x02,
		0x60, 0x01, 0x7f, 0x01, 0x7f,
		0x60, 0x02, 0x7f, 0x7f, 0x01, 0x7e,
		0x03, 0x03, 0x02, 0x00, 0x01,
		0x05, 0x03, 0x01, 0x00, 0x01,
		0x07, 0x1e, 0x03,
		0x06, 0x6d, 0x65, 0x6d, 0x6f, 0x72, 0x79, 0x02, 0x00,
		0x05, 0x61, 0x6c, 0x6c, 0x6f, 0x63, 0x00, 0x00,
		0x09, 0x74, 0x72, 0x61, 0x6e, 0x73, 0x66, 0x6f, 0x72, 0x6d, 0x00, 0x01,
		// code section: 2 functions
		0x0a, 0x13, 0x02,
		// alloc body: i32.const 0, end
		0x04, 0x00, 0x41, 0x00, 0x0b,
		// transform body: block { loop { br 0 } } i64.const 0 end
		// size=12, 0 locals
		0x0c, 0x00,
		0x02, 0x40, // block (void)
		0x03, 0x40, // loop (void)
		0x0c, 0x00, // br 0 (loop back)
		0x0b,       // end (loop)
		0x0b,       // end (block)
		0x42, 0x00, // i64.const 0
		0x0b,       // end
	}

	// import_denied.wasm — imports env.log; alloc and transform return 0.
	importDeniedWASM := []byte{
		0x00, 0x61, 0x73, 0x6d, 0x01, 0x00, 0x00, 0x00,
		// type section: type[0] (i32,i32)->void, type[1] (i32)->i32, type[2] (i32,i32)->i64
		0x01, 0x11, 0x03,
		0x60, 0x02, 0x7f, 0x7f, 0x00,
		0x60, 0x01, 0x7f, 0x01, 0x7f,
		0x60, 0x02, 0x7f, 0x7f, 0x01, 0x7e,
		// import section: (env, "log", func type[0])
		0x02, 0x0b, 0x01,
		0x03, 0x65, 0x6e, 0x76, // "env"
		0x03, 0x6c, 0x6f, 0x67, // "log"
		0x00, 0x00, // func, type[0]
		// function section: func[1]=type[1] (alloc), func[2]=type[2] (transform)
		0x03, 0x03, 0x02, 0x01, 0x02,
		// memory section
		0x05, 0x03, 0x01, 0x00, 0x01,
		// export section: "memory" mem[0], "alloc" func[1], "transform" func[2]
		0x07, 0x1e, 0x03,
		0x06, 0x6d, 0x65, 0x6d, 0x6f, 0x72, 0x79, 0x02, 0x00,
		0x05, 0x61, 0x6c, 0x6c, 0x6f, 0x63, 0x00, 0x01,
		0x09, 0x74, 0x72, 0x61, 0x6e, 0x73, 0x66, 0x6f, 0x72, 0x6d, 0x00, 0x02,
		// code section: 2 defined funcs (alloc + transform)
		0x0a, 0x0b, 0x02,
		0x04, 0x00, 0x41, 0x00, 0x0b, // alloc: i32.const 0
		0x04, 0x00, 0x42, 0x00, 0x0b, // transform: i64.const 0
	}

	must := func(err error) {
		if err != nil {
			panic(err)
		}
	}
	must(os.WriteFile("echo_transform.wasm", echoTransformWASM, 0644))
	must(os.WriteFile("infinite_loop.wasm", infiniteLoopWASM, 0644))
	must(os.WriteFile("import_denied.wasm", importDeniedWASM, 0644))
}
